    // 分页
    contentPageStyleChange(){
      let arr = []

      if(this.contents.pageTotal) arr.push('total')
      if(this.contents.pageSizes) arr.push('sizes')
      if(this.contents.pagePrevNext){
        arr.push('prev')
        if(this.contents.pagePager) arr.push('pager')
        arr.push('next')
      }
      if(this.contents.pageJumper) arr.push('jumper')
      this.layouts = arr.join()
      this.contents.pageEachNum = 10
    },

    huiyuanquxiaoCrossAddOrUpdateHandler(row,type){
      this.showFlag = false;
      this.addOrUpdateFlag = false;
      this.huiyuanquxiaoCrossAddOrUpdateFlag = true;
      this.$storage.set('crossObj',row);
      this.$storage.set('crossTable','huiyuanyuyue');
      this.$nextTick(() => {
      this.$refs.huiyuanquxiaoCrossaddOrUpdate.init(row.id,type);
      });
    },
    checkInHandler(row) {
      this.$confirm(`确定为预约 ${row.yuyuebianhao} 办理入住吗？\n客房号：${row.kefanghao}\n会员：${row.xingming}（会员享受9折优惠）`, "办理入住确认", {
        confirmButtonText: "确定办理",
        cancelButtonText: "取消",
        type: "info"
      }).then(() => {
        this.$http({
          url: `huiyuanruzhu/checkInByYuyue/${row.id}`,
          method: "post"
        }).then(({ data }) => {
          if (data && data.code === 0) {
            this.$message({
              message: data.msg || "入住办理成功",
              type: "success",
              duration: 2000,
              onClose: () => {
                this.getDataList();
              }
            });
          } else {
            this.$message.error(data.msg || "办理入住失败");
          }
        });
      }).catch(() => {});
    },
    confirmRefundHandler(row) {
      this.$confirm(`确定已为订单 ${row.yuyuebianhao} 完成退款处理吗？`, "确认退款", {
        confirmButtonText: "确定",
        cancelButtonText: "取消",
        type: "warning"
      }).then(() => {
        this.$http({
          url: `huiyuanyuyue/confirmRefund/${row.id}`,
          method: "post"
        }).then(({ data }) => {
          if (data && data.code === 0) {
            this.$message.success(data.msg || "退款已确认");
            this.getDataList();
          } else {
            this.$message.error(data.msg || "操作失败");
          }
        });
      }).catch(() => {});
    },
    payHandler(row){
      this.$storage.set('paytable','huiyuanyuyue');
      this.$storage.set('payObject',row);
      this.$router.push('pay');
    },
    init () {
    },
    search() {
      this.pageIndex = 1;
      this.getDataList();
    },
    // 获取数据列表
    getDataList() {
      this.dataListLoading = true;
      let params = {
        page: this.pageIndex,
        limit: this.pageSize,
        sort: 'id',
      }
          if(this.searchForm.kefanghao!='' && this.searchForm.kefanghao!=undefined){
            params['kefanghao'] = '%' + this.searchForm.kefanghao + '%'
          }
          if(this.searchForm.xingming!='' && this.searchForm.xingming!=undefined){
            params['xingming'] = '%' + this.searchForm.xingming + '%'
          }
      this.$http({
        url: "huiyuanyuyue/page",
        method: "get",
        params: params
      }).then(({ data }) => {
        if (data && data.code === 0) {
          this.dataList = data.data.list;
          this.totalPage = data.data.total;
        } else {
          this.dataList = [];
          this.totalPage = 0;
        }
        this.dataListLoading = false;
      });
    },
    // 每页数
    sizeChangeHandle(val) {
      this.pageSize = val;
      this.pageIndex = 1;
      this.getDataList();
    },
    // 当前页
    currentChangeHandle(val) {
      this.pageIndex = val;
      this.getDataList();
    },
    // 多选
    selectionChangeHandler(val) {
      this.dataListSelections = val;
    },
    // 添加/修改
    addOrUpdateHandler(id,type) {
      this.showFlag = false;
      this.addOrUpdateFlag = true;
      this.crossAddOrUpdateFlag = false;
      if(type!='info'){
        type = 'else';
      }
      this.$nextTick(() => {
        this.$refs.addOrUpdate.init(id,type);
      });
    },
    // 查看评论
    // 审核窗口
    shDialog(row){
      this.sfshVisiable = !this.sfshVisiable;
      if(row){
        this.shForm = {
          yuyuebianhao: row.yuyuebianhao,
          kefanghao: row.kefanghao,
          ruzhushijian: row.ruzhushijian,
          jiage: row.jiage,
          tianshu: row.tianshu,
          zongjia: row.zongjia,
          yuyueshijian: row.yuyueshijian,
          zhanghao: row.zhanghao,
          xingming: row.xingming,
          shouji: row.shouji,
          shenfenzheng: row.shenfenzheng,
          sfsh: row.sfsh,
          shhf: row.shhf,
          ispay: row.ispay,
          id: row.id
        }
      }
    },
    // 审核
    shHandler(){
      this.$confirm(`确定操作?`, "提示", {
        confirmButtonText: "确定",
        cancelButtonText: "取消",
        type: "warning"
      }).then(() => {
        this.$http({
          url: "huiyuanyuyue/audit/" + this.shForm.id,
          method: "post",
          data: {
            sfsh: this.shForm.sfsh,
            shhf: this.shForm.shhf
          }
        }).then(({ data }) => {
          if (data && data.code === 0) {
            this.$message({
              message: "审核成功",
              type: "success",
              duration: 1500,
              onClose: () => {
                this.getDataList();
                this.shDialog()
              }
            });
          } else {
            this.$message.error(data.msg);
          }
        });
      });
    },
    // 下载
    download(file){
      window.open(`${file}`)
    },
    // 删除
    deleteHandler(id) {
      var ids = id
        ? [Number(id)]
        : this.dataListSelections.map(item => {
            return Number(item.id);
          });
      this.$confirm(`确定进行[${id ? "删除" : "批量删除"}]操作?`, "提示", {
        confirmButtonText: "确定",
        cancelButtonText: "取消",
        type: "warning"
      }).then(() => {
        this.$http({
          url: "huiyuanyuyue/delete",
          method: "post",
          data: ids
        }).then(({ data }) => {
          if (data && data.code === 0) {
            this.$message({
              message: "操作成功",
              type: "success",
              duration: 1500,
              onClose: () => {
                this.search();
              }
            });
          } else {
            this.$message.error(data.msg);
          }
        });
      });
    },
  }

};
